class Handler(BaseHTTPRequestHandler):
    def log_message(self, *a):  # silence les logs HTTP
        pass

    def _send(self, code, body, ctype):
        self.send_response(code)
        self.send_header("Content-Type", ctype)
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def do_GET(self):
        path = self.path.split("?")[0]
        if path == "/" or path == "/index.html":
            if os.path.exists("dashboard.html"):
                with open("dashboard.html", "rb") as f:
                    self._send(200, f.read(), "text/html; charset=utf-8")
            else:
                self._send(200, base64.b64decode(HTML_B64), "text/html; charset=utf-8")
            return
        if path == "/api/assets":
            body = json.dumps([{"id": k, "label": v["label"],
                                "cat": v.get("cat", "macro"), "group": v.get("group", ""),
                                "ticker": (v["cboe"].lstrip("_") if v.get("source") == "cboe" and v.get("cboe") else k)}
                               for k, v in fe.ASSETS.items()])
            self._send(200, body.encode(), "application/json")
            return
        if path.startswith("/api/"):
            import urllib.parse
            asset = urllib.parse.unquote(path.split("/api/")[1]).upper()
            qs = urllib.parse.parse_qs(self.path.split("?")[1]) if "?" in self.path else {}
            dte = qs.get("dte", [None])[0]
            fresh = qs.get("fresh", [None])[0]
            sign = qs.get("sign", [None])[0]              # "fixed" | "adaptive" | None(=réglage global)
            if sign not in ("fixed", "adaptive"):
                sign = None
            ck = f"{asset}:{dte}:{sign}"                  # le mode fait partie de la clé de cache
            now = time.time()
            if not fresh and ck in _CACHE and now - _CACHE[ck][0] < _TTL:
                self._send(200, _CACHE[ck][1], "application/json")
                return
            try:
                data = fe.analyse(asset, dte_days=dte, sign_mode=sign)
                body = json.dumps(data, default=str).encode()
                _CACHE[ck] = (now, body)
                self._send(200, body, "application/json")
            except Exception as e:
                traceback.print_exc()
                self._send(500, json.dumps({"error": str(e)}).encode(), "application/json")
            return
        self._send(404, b"not found", "text/plain")


def local_ip():
    try:
        s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        s.connect(("8.8.8.8", 80))
        ip = s.getsockname()[0]
        s.close()
        return ip
    except Exception:
        return "127.0.0.1"


def open_browser():
    time.sleep(1.2)
    try:
        webbrowser.open(f"http://localhost:{PORT}")
    except Exception:
        pass


if __name__ == "__main__":
    ip = local_ip()
    print("\n  Flow Engine - dashboard")
    print(f"  Sur ce PC          : http://localhost:{PORT}")
    print(f"  Sur le reseau local: http://{ip}:{PORT}   (tel, autre PC du meme wifi)")
    print("  (Chrome s'ouvre tout seul. Laisse cette fenetre OUVERTE.)\n")
    threading.Thread(target=open_browser, daemon=True).start()
    try:
        ThreadingHTTPServer(("0.0.0.0", PORT), Handler).serve_forever()
    except OSError as e:
        print(f"[ERREUR] Port {PORT} deja utilise ou bloque : {e}")
        input("Appuie sur Entree pour fermer...")
